const ctx = items[0].json;

function nowIso() { return new Date().toISOString(); }
function ensureArray(value) { return Array.isArray(value) ? value : []; }
function shortText(value, maxLen = 240) {
  const text = typeof value === 'string' ? value : JSON.stringify(value || '');
  return text.length <= maxLen ? text : text.slice(0, maxLen - 3) + '...';
}

async function callSearx(query) {
  const maxAttempts = 4;
  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      return await this.helpers.httpRequest({
        method: 'GET',
        url: 'http://searxng:8080/search',
        qs: { format: 'json', language: 'de-DE', q: query },
        headers: { 'User-Agent': 'Mozilla/5.0 (sandbank-workflow-research)' },
        json: true,
      });
    } catch (error) {
      const status = error?.response?.status || error?.httpCode || 0;
      if (status === 429 && attempt < maxAttempts) {
        await new Promise((resolve) => setTimeout(resolve, 450 * attempt));
        continue;
      }
      throw new Error('SearXNG failed for query "' + query + '": ' + (error.message || 'request error'));
    }
  }
  throw new Error('SearXNG failed after retries for query "' + query + '"');
}

async function callQwenSummary(payload) {
  const prompt = [
    ctx.prompts.qwen_step_summary,
    'Payload: ' + shortText(payload, 2200),
    'Antworte knapp in 1-2 Saetzen.',
  ].join('\n\n');
  try {
    const data = await this.helpers.httpRequest({
      method: 'POST',
      url: (($env.OLLAMA_BASE_URL || 'http://host.docker.internal:11434').replace(/\/+$/, '') + '/api/chat'),
      body: {
        model: ctx.model_used,
        stream: false,
        keep_alive: '30m',
        messages: [
          { role: 'system', content: 'Du schreibst knappe Workflow-Zusammenfassungen. Keine Listen.' },
          { role: 'user', content: prompt },
        ],
        options: { temperature: 0.1, num_predict: 40, num_ctx: 256 },
      },
      json: true,
      timeout: 90000,
    });
    return shortText((data?.message?.content || data?.response || '').replace(/\s+/g, ' ').trim(), 280);
  } catch (error) {
    return 'Zusammenfassung fehlgeschlagen: ' + shortText(error.message || 'unknown', 160);
  }
}

function addStage(step, stage, status, inputRef, outputRef, quality, notes, issueCount = 0) {
  ctx.stage_logs.push({
    step,
    stage,
    status,
    input_ref: inputRef,
    output_ref: outputRef,
    quality_score: Number.isFinite(Number(quality)) ? Number(quality) : 0,
    notes: String(notes || ''),
    issues: Number.isFinite(Number(issueCount)) ? Number(issueCount) : 0,
    model_used: ctx.model_used,
    ts: nowIso(),
  });
  ctx.model_trace = ensureArray(ctx.model_trace);
  ctx.model_trace.push({ step, stage, model_used: ctx.model_used, ts: nowIso() });
}

function avg(values) {
  if (!values.length) return 0;
  return values.reduce((a, b) => a + b, 0) / values.length;
}

const baseQueries = [
  ctx.topic_hint ? String(ctx.topic_hint) + ' b2b datenanalyse praxis' : null,
  'b2b analytics reporting pain points 2026',
  'data infrastructure saas trends 2026',
  'site:reddit.com dataengineering dashboard reporting',
  'site:reddit.com SideProject openrouter exa serp',
].filter(Boolean);

const rawSignals = [];
const failedQueries = [];

for (const query of baseQueries.slice(0, 4)) {
  try {
    const response = await callSearx.call(this, query);
    const results = ensureArray(response.results).slice(0, 4);
    for (const result of results) {
      rawSignals.push({
        query,
        source_type: query.includes('site:reddit.com') ? 'searx_reddit' : 'web',
        title: String(result.title || ''),
        url: String(result.url || ''),
        summary: String(result.content || result.snippet || ''),
        published_at: String(result.publishedDate || ''),
      });
    }
  } catch (error) {
    failedQueries.push({ query, reason: String(error.message || 'unknown') });
  }
}

if (!rawSignals.length) {
  throw new Error('No research signals collected. Failed queries: ' + JSON.stringify(failedQueries));
}

ctx.artifacts.raw_signals = rawSignals;
addStage(
  1,
  'collect_research_daten',
  'ok',
  'run/' + ctx.run_id + '/stage1/input',
  'run/' + ctx.run_id + '/stage1/raw_signals',
  rawSignals.length >= 6 ? 8.5 : 6.5,
  'signals=' + rawSignals.length + '; failed_queries=' + failedQueries.length,
  failedQueries.length,
);
ctx.stage_summaries.push({
  step: 1,
  stage: 'collect_research_daten',
  summary: await callQwenSummary.call(this, JSON.stringify(rawSignals.slice(0, 6))),
});

const evidencePackets = rawSignals.slice(0, 12).map((signal) => {
  const pointA = shortText(signal.title || 'Signal ohne Titel', 120);
  const pointB = shortText(signal.summary || 'Keine Zusammenfassung verfuegbar.', 140);
  const isReddit = String(signal.source_type || '').includes('reddit');
  return {
    query: String(signal.query || ''),
    source_type: String(signal.source_type || 'web'),
    title: String(signal.title || ''),
    url: String(signal.url || ''),
    published_at: String(signal.published_at || ''),
    summary: String(signal.summary || ''),
    key_points: [pointA, pointB].filter(Boolean),
    icp_fit_score: isReddit ? 0.62 : 0.74,
    product_relevance_score: isReddit ? 0.58 : 0.71,
    evidence_strength: String(signal.url || '').startsWith('http') ? 0.69 : 0.48,
    risk_notes: [isReddit ? 'community_signal' : 'web_signal'],
  };
});

ctx.artifacts.evidence_packets = evidencePackets;
addStage(
  2,
  'build_evidence_paket',
  'ok',
  'run/' + ctx.run_id + '/stage2/input',
  'run/' + ctx.run_id + '/stage2/evidence_packets',
  avg(evidencePackets.map((p) => p.evidence_strength)),
  'packets=' + evidencePackets.length,
);
ctx.stage_summaries.push({
  step: 2,
  stage: 'build_evidence_paket',
  summary: await callQwenSummary.call(this, JSON.stringify(evidencePackets.slice(0, 4))),
});

return [{ json: ctx }];
